// @arche/concurrency - lightweight, non-viral structured concurrency for TypeScript.
// Implemented incrementally via TDD; see DESIGN.md for the full spec.

export {};

import { describe, expect, test } from "bun:test";
import { CoroutineAlreadyStartedError, io } from "./index";

describe("coroutine lifecycle", () => {
  test("coroutine is lazy: the body does not run until spawn()", async () => {
    let ran = false;
    const coro = io.coroutine(async () => {
      ran = true;
      return 1;
    });
    expect(ran).toBe(false);
    await coro.spawn();
    expect(ran).toBe(true);
  });

  test("await spawn() resolves to the body's return value", async () => {
    const coro = io.coroutine(async () => "hello");
    expect(await coro.spawn()).toBe("hello");
  });

  test("a second spawn() throws CoroutineAlreadyStartedError", async () => {
    const coro = io.coroutine(async () => "x");
    const handle = coro.spawn();
    expect(() => coro.spawn()).toThrow(CoroutineAlreadyStartedError);
    await handle;
  });
});

export class ConcurrencyError extends Error {
  readonly code: string;

  constructor(message: string, code: string) {
    super(message);
    this.name = new.target.name;
    this.code = code;
  }
}

export class CancelledError extends ConcurrencyError {
  constructor(message = "coroutine cancelled") {
    super(message, "cancelled");
  }
}

export class CoroutineAlreadyStartedError extends ConcurrencyError {
  constructor(message = "coroutine already started") {
    super(message, "already_started");
  }
}

/**
 * The read-only context handed to a coroutine body (and to a `defer` callback).
 * Spawning children is not on `ctx` - use the ambient `io.*` helpers; the scope
 * is wired through `AsyncLocalStorage`.
 */
export interface Ctx {
  /** Aborts when this unit of work is cancelled. Thread into raw async (`fetch(url, { signal })`). */
  readonly signal: AbortSignal;
  /** `=== signal.aborted`. */
  readonly cancelled: boolean;
  /** Cooperative checkpoint for tight sync loops / raw promises: throws `CancelledError` if cancelled. */
  throwIfCancelled(): void;
  /** Optional label for diagnostics (zombie / unhandled-error logs). */
  readonly name?: string;
}

export type CoroutineBody<T> = (ctx: Ctx) => Promise<T>;

/** An inert, one-shot, non-thenable coroutine specification. */
export interface Coroutine<T> {
  /** Start the coroutine exactly once. A second call throws `CoroutineAlreadyStartedError`. */
  spawn(): RoutineHandle<T>;
}

/** A running coroutine instance: awaitable (thenable) and cancellable. */
export interface RoutineHandle<T> extends PromiseLike<T> {
  /** Request cancellation; fire-and-forget. Idempotent. */
  cancel(): void;
  /** Request cancellation and await teardown completion. Idempotent. */
  cancelGracefully(): Promise<void>;
  readonly cancelled: boolean;
}

import { CancelledError, CoroutineAlreadyStartedError } from "./errors";
import type { Coroutine, CoroutineBody, Ctx, RoutineHandle } from "./types";

function makeCtx(signal: AbortSignal, name?: string): Ctx {
  return {
    signal,
    get cancelled() {
      return signal.aborted;
    },
    throwIfCancelled() {
      if (signal.aborted) throw new CancelledError();
    },
    name,
  };
}

class RoutineHandleImpl<T> implements RoutineHandle<T> {
  readonly #promise: Promise<T>;
  readonly #controller: AbortController;

  constructor(promise: Promise<T>, controller: AbortController) {
    this.#promise = promise;
    this.#controller = controller;
  }

  then<R1 = T, R2 = never>(
    onfulfilled?: ((value: T) => R1 | PromiseLike<R1>) | null,
    onrejected?: ((reason: unknown) => R2 | PromiseLike<R2>) | null,
  ): Promise<R1 | R2> {
    return this.#promise.then(onfulfilled, onrejected);
  }

  cancel(): void {
    this.#controller.abort();
  }

  async cancelGracefully(): Promise<void> {
    this.#controller.abort();
    await this.#promise.catch(() => {});
  }

  get cancelled(): boolean {
    return this.#controller.signal.aborted;
  }
}

class CoroutineImpl<T> implements Coroutine<T> {
  readonly #body: CoroutineBody<T>;
  #started = false;

  constructor(body: CoroutineBody<T>) {
    this.#body = body;
  }

  spawn(): RoutineHandle<T> {
    if (this.#started) throw new CoroutineAlreadyStartedError();
    this.#started = true;
    const controller = new AbortController();
    const ctx = makeCtx(controller.signal);
    const promise = this.#body(ctx);
    return new RoutineHandleImpl(promise, controller);
  }
}

export function coroutine<T>(body: CoroutineBody<T>): Coroutine<T> {
  return new CoroutineImpl(body);
}

