import { CancelledError, io } from "./index";

async function caught(p: PromiseLike<unknown>): Promise<unknown> {
  try {
    await p;
    return undefined;
  } catch (e) {
    return e;
  }
}

describe("cancellation", () => {
  test("cancel() makes an in-flight sleep reject the body with CancelledError", async () => {
    const handle = io
      .coroutine(async () => {
