import { CancelledError, CoroutineAlreadyStartedError } from "./errors";
import { runInScope, type Scope } from "./scope";
import type { Coroutine, CoroutineBody, Ctx, DeferCallback, RoutineHandle } from "./types";

function makeCtx(signal: AbortSignal, name?: string): Ctx {
  return {
    signal,
    get cancelled() {
      return signal.aborted;
    },
    throwIfCancelled() {
      if (signal.aborted) throw new CancelledError();
    },
    name,
  };
}

/**
 * Run a coroutine body, then its deferred cleanups, LIFO. Cleanups run shielded
 * under a fresh, non-aborted signal so they can do bounded async work even when
 * the coroutine was cancelled.
 */
async function runWithDefers<T>(body: CoroutineBody<T>, ctx: Ctx, scope: Scope): Promise<T> {
  let result: T;
  let bodyError: unknown;
  let failed = false;
  try {
    result = await runInScope(scope, () => body(ctx));
  } catch (error) {
    failed = true;
    bodyError = error;
  }

  await runDefers(scope.defers);

  if (failed) throw bodyError;
  return result as T;
}

async function runDefers(defers: readonly DeferCallback[]): Promise<void> {
  if (defers.length === 0) return;
  const cleanupController = new AbortController();
  const cleanupScope: Scope = { signal: cleanupController.signal, defers: [] };
  const cleanupCtx = makeCtx(cleanupController.signal);
  await runInScope(cleanupScope, async () => {
    for (let i = defers.length - 1; i >= 0; i--) {
      try {
        await defers[i]?.(cleanupCtx);
      } catch {
        // Cleanup is best-effort; a failing defer must not abort the remaining chain.
      }
    }
  });
}

