          defer(() => order.push("child cleanup"));
          io.coroutine(async () => {
            defer(() => order.push("grandchild cleanup"));
            await io.sleep(1000);
          }).spawn();
          await io.sleep(1000);
        }).spawn();
        // give the grandchild a tick to spawn before the parent returns
        await io.sleep(10);
