import { describe, expect, test } from "bun:test";
import { CancelledError, defer, io } from "./index";

async function caught(p: PromiseLike<unknown>): Promise<unknown> {
  try {
    await p;
    return undefined;
  } catch (e) {
    return e;
  }
}

describe("io.all", () => {
  test("resolves with results in input order when all succeed", async () => {
    const result = await io.all([
      io.coroutine(async () => {
        await io.sleep(20);
        return "a";
      }),
      io.coroutine(async () => {
        await io.sleep(5);
        return "b";
      }),
    ]);
    expect(result).toEqual(["a", "b"]);
  });

  test("fail-fast: the first rejection tears down the siblings and rejects with that error", async () => {
    const cleaned: string[] = [];
    const boom = new Error("boom");
    const handle = io.all([
      io.coroutine(async () => {
        await io.sleep(5);
        throw boom;
      }),
      io.coroutine(async () => {
        defer(() => cleaned.push("b cleaned"));
        await io.sleep(1000);
        return "b";
      }),
    ]);
    expect(await caught(handle)).toBe(boom);
    expect(cleaned).toEqual(["b cleaned"]);
  });

  test("cancelling the io.all handle cancels every member", async () => {
    const cleaned: string[] = [];
    const handle = io.all([
      io.coroutine(async () => {
        defer(() => cleaned.push("a"));
        await io.sleep(1000);
      }),
      io.coroutine(async () => {
        defer(() => cleaned.push("b"));
        await io.sleep(1000);
      }),
    ]);
    handle.cancel();
    expect(await caught(handle)).toBeInstanceOf(CancelledError);
    expect([...cleaned].sort()).toEqual(["a", "b"]);
  });
});

import { coroutine } from "./coroutine";
import type { Coroutine, RoutineHandle } from "./types";

/**
 * Run all coroutines concurrently and resolve with their results in input order.
 *
 * Fail-fast: the first member to reject settles the handle with that error, and
 * the remaining members are torn down (their cleanups run) by the structured
 * teardown of the enclosing coroutine. Cancelling the returned handle cancels
 * every member.
 */
export function all<T>(coros: Coroutine<T>[]): RoutineHandle<T[]> {
  return coroutine(() => Promise.all(coros.map((c) => c.spawn()))).spawn();
}

