/**
 * Run `factory()` (a fresh coroutine per attempt), retrying on failure up to
 * `retries` times. Resolves with the first successful value; rejects with the
 * last error once retries are exhausted or `shouldRetry` returns false.
 *
 * Cancellation is terminal: a `CancelledError` is never retried, and cancelling
 * the returned handle stops the in-flight attempt and any backoff sleep.
 */
export function withRetry<T>(factory: () => Coroutine<T>, opts: RetryOptions): RoutineHandle<T> {
  const { retries, delayMs = 0, factor = 1, shouldRetry } = opts;
  return coroutine(async () => {
    for (let attempt = 0; ; attempt++) {
      try {
        return await factory().spawn();
      } catch (error) {
        if (error instanceof CancelledError) throw error;
        const canRetry = attempt < retries && (shouldRetry ? shouldRetry(error, attempt) : true);
        if (!canRetry) throw error;
        if (delayMs > 0) await sleep(delayMs * factor ** attempt);
      }
    }
  }).spawn();
}

