/**
 * Make awaiting an arbitrary promise cancellable by the ambient scope: the
 * returned promise settles with the source, OR rejects with `CancelledError`
 * the moment the current coroutine is cancelled — whichever happens first.
 *
 * Outside a coroutine there is no scope to observe, so the source is returned
 * unchanged (non-cancellable). The source promise is left intact; cancelling the
 * wait does not cancel the underlying work.
 */
export function cancellable<T>(promise: PromiseLike<T>): Promise<T> {
  const signal = currentScope()?.signal;
  if (!signal) return Promise.resolve(promise);
  if (signal.aborted) return Promise.reject(new CancelledError());

  return new Promise<T>((resolve, reject) => {
    const onAbort = () => reject(new CancelledError());
    signal.addEventListener("abort", onAbort, { once: true });
    promise.then(
      (value) => {
        signal.removeEventListener("abort", onAbort);
        resolve(value);
      },
      (error) => {
        signal.removeEventListener("abort", onAbort);
        reject(error);
      },
    );
  });
}

/**
 * A write-once, externally-settled awaitable. `resolve`/`reject` settle it; the
 * first call wins and later calls are silent no-ops. Awaiting it inside a
 * coroutine is cancellable via the ambient scope.
 */
export interface Future<T> extends PromiseLike<T> {
  /** Settle with a value. No-op if already settled. */
  resolve(value: T): void;
  /** Settle with an error. No-op if already settled. */
  reject(error: unknown): void;
  /** Whether `resolve` or `reject` has been called. */
  readonly settled: boolean;
}

