import type { Future } from "./types";
import { cancellable } from "./utils";

class FutureImpl<T> implements Future<T> {
  #settled = false;
  #resolve!: (value: T) => void;
  #reject!: (error: unknown) => void;
  readonly #promise: Promise<T>;

  constructor() {
    this.#promise = new Promise<T>((resolve, reject) => {
      this.#resolve = resolve;
      this.#reject = reject;
    });
    // Guard against an unhandled rejection when the future is rejected but never
    // awaited; real consumers still see the rejection via their own `then`.
    void this.#promise.catch(() => {});
  }

  get settled(): boolean {
    return this.#settled;
  }

  resolve(value: T): void {
    if (this.#settled) return;
    this.#settled = true;
    this.#resolve(value);
  }

  reject(error: unknown): void {
    if (this.#settled) return;
    this.#settled = true;
    this.#reject(error);
  }

  // biome-ignore lint/suspicious/noThenProperty: a Future is intentionally thenable (PromiseLike) so it can be awaited.
  then<R1 = T, R2 = never>(
    onFulfilled?: ((value: T) => R1 | PromiseLike<R1>) | null,
    onRejected?: ((reason: unknown) => R2 | PromiseLike<R2>) | null,
  ): Promise<R1 | R2> {
    return cancellable(this.#promise).then(onFulfilled, onRejected);
  }
}

/** Create a {@link Future}: an externally resolved/rejected, cancellable awaitable. */
export function future<T>(): Future<T> {
  return new FutureImpl<T>();
}

