import { describe, expect, test } from "bun:test";
import { CancelledError, io } from "./index";

async function caught(p: PromiseLike<unknown>): Promise<unknown> {
  try {
    await p;
    return undefined;
  } catch (e) {
    return e;
  }
}

describe("io.mutex", () => {
  test("serializes runExclusive sections (no overlap)", async () => {
    const m = io.mutex();
    const order: string[] = [];
    const a = m.runExclusive(async () => {
      order.push("a-start");
      await io.sleep(10);
      order.push("a-end");
    });
    const b = m.runExclusive(async () => {
      order.push("b-start");
      await io.sleep(1);
      order.push("b-end");
    });
    await Promise.all([a, b]);
    expect(order).toEqual(["a-start", "a-end", "b-start", "b-end"]);
  });

  test("runExclusive returns fn's value", async () => {
    const m = io.mutex();
    expect(await m.runExclusive(() => 42)).toBe(42);
  });

  test("runExclusive releases the permit even when fn throws", async () => {
    const m = io.mutex();
    const boom = new Error("boom");
    expect(await caught(m.runExclusive(() => {
      throw boom;
    }))).toBe(boom);
    expect(m.available).toBe(1);
  });

  test("the release token is idempotent", async () => {
    const m = io.mutex();
    const release = await m.acquire();
    expect(m.available).toBe(0);
    release();
    release();
    expect(m.available).toBe(1);
  });

  test("waiters acquire in FIFO order", async () => {
    const m = io.mutex();
    const held = await m.acquire();
    const order: number[] = [];
    const w1 = m.acquire().then((r) => {
      order.push(1);
      return r;
    });
    const w2 = m.acquire().then((r) => {
      order.push(2);
      return r;
    });
    held(); // wakes w1
    (await w1)(); // w1 releases -> wakes w2
    await w2;
    expect(order).toEqual([1, 2]);
  });

  test("a blocked acquire is cancellable and does not steal the permit", async () => {
    const m = io.mutex();
    await m.acquire(); // lock held
    const handle = io
      .coroutine(async () => {
        const release = await m.acquire(); // parks
        release();
      })
      .spawn();
    handle.cancel();
    expect(await caught(handle)).toBeInstanceOf(CancelledError);
    expect(m.available).toBe(0);
  });
});

describe("io.semaphore", () => {
  test("allows up to n holders concurrently and blocks the next", async () => {
    const s = io.semaphore(2);
    const r1 = await s.acquire();
    const r2 = await s.acquire();
    expect(s.available).toBe(0);

    let third = false;
    const pending = s.acquire().then((r) => {
      third = true;
      return r;
    });
    await Promise.resolve();
    expect(third).toBe(false);

    r1(); // hands the permit to the parked third acquirer
    const r3 = await pending;
    expect(third).toBe(true);

    r2();
    r3();
    expect(s.available).toBe(2);
  });
});

import { AsyncLocalStorage } from "node:async_hooks";
import { CancelledError } from "./errors";
import type { Ctx, DeferCallback } from "./types";

/** The minimal child surface a scope needs to enforce strict structured concurrency. */
export interface ChildHandle {
  cancel(): void;
  cancelGracefully(opts?: { timeoutMs?: number }): Promise<void>;
}

/**
 * The ambient state a coroutine body runs within. Propagated implicitly through
 * `AsyncLocalStorage` so framework operations (`io.sleep`, channel ops, ...) can
 * observe cancellation without being handed a signal.
 */
export interface Scope {
  readonly signal: AbortSignal;
  /** The context returned by `io.context()` for code running within this scope. */
  readonly ctx: Ctx;
  /** Deferred cleanups registered via `defer`, run LIFO when the scope unwinds. */
  readonly defers: DeferCallback[];
  /**
   * Coroutines spawned within this scope. Strict structured concurrency: a child's
   * lifetime cannot outlive its parent, so any still-running child is halted (and
   * awaited) when this scope exits, before this scope's own defers run.
   */
  readonly children: Set<ChildHandle>;
}

export function makeCtx(signal: AbortSignal, name?: string): Ctx {
  return {
    signal,
    get cancelled() {
      return signal.aborted;
    },
    throwIfCancelled() {
      if (signal.aborted) throw new CancelledError();
    },
    name,
  };
}

const storage = new AsyncLocalStorage<Scope>();

export function runInScope<T>(scope: Scope, fn: () => Promise<T>): Promise<T> {
  return storage.run(scope, fn);
}

export function currentScope(): Scope | undefined {
  return storage.getStore();
}

// The root scope is the implicit parent of every top-level coroutine, so a single
// `io.cancelGlobal()` can tear the whole tree down. It is swappable (`resetRoot`)
// so global cancellation leaves a fresh, usable root behind.
let rootController: AbortController;
let rootScopeInstance: Scope;

function createRoot(): void {
  rootController = new AbortController();
  rootScopeInstance = {
    signal: rootController.signal,
    ctx: makeCtx(rootController.signal, "root"),
    defers: [],
    children: new Set(),
  };
}
createRoot();

export function rootScope(): Scope {
  return rootScopeInstance;
}

export function abortRoot(): void {
  rootController.abort();
}

export function resetRoot(): void {
  createRoot();
}

