/**
 * Spawn many coroutines as fire-and-forget background work, parented to the
 * current scope so they are torn down when it exits. The returned handle may be
 * awaited for results, but the common case is to ignore it: a non-cancellation
 * failure is surfaced to the log rather than as an unhandled rejection.
 */
export function background<T>(coros: Coroutine<T>[]): RoutineHandle<T[]> {
  const handle = all(coros);
  void Promise.resolve(handle).catch((error) => {
    // Cancellation is the normal teardown path when the parent scope exits.
    if (error instanceof CancelledError) return;
    log.error("unhandled error in background coroutine(s)", {
      code: "background_error",
      error: error instanceof Error ? error.message : String(error),
    });
  });
  return handle;
}

